    renderLogs(logs) {
        const container = document.getElementById('logs-container');
        container.innerHTML = '';

        // Add summary section
        if (logs.summary) {
            const summaryDiv = document.createElement('div');
            summaryDiv.className = 'log-summary';
            summaryDiv.innerHTML = `
                <h4>📊 Operations Summary</h4>
                <div class="summary-stats">
                    <span>Total: ${logs.summary.total}</span>
                    <span>Last Hour: ${logs.summary.lastHour}</span>
                    <span>Last 24h: ${logs.summary.last24Hours}</span>
                </div>
            `;
            container.appendChild(summaryDiv);
        }

        // Add filter buttons
        const filterDiv = document.createElement('div');
        filterDiv.className = 'log-filters';
        filterDiv.innerHTML = `
            <button onclick="window.app.filterLogs('all')" class="filter-btn active">All</button>
            <button onclick="window.app.filterLogs('operations')" class="filter-btn">Operations</button>
            <button onclick="window.app.filterLogs('system')" class="filter-btn">System</button>
            <button onclick="window.app.filterLogs('errors')" class="filter-btn">Errors</button>
        `;
        container.appendChild(filterDiv);

        // Create scrollable log container
        const logList = document.createElement('div');
        logList.className = 'log-list';
        logList.id = 'log-list';

        // Render operations first (more important)
        if (logs.operations && logs.operations.length > 0) {
            const opsHeader = document.createElement('h5');
            opsHeader.textContent = '🔌 Plugin Operations';
            opsHeader.className = 'log-section-header operations-section';
            logList.appendChild(opsHeader);

            logs.operations.forEach(op => {
                const entry = document.createElement('div');
                entry.className = `log-entry operation-log ${op.status}`;
                entry.dataset.logType = 'operations';
                entry.innerHTML = `
                    <span class="log-time">${op.time}</span>
                    <span class="log-type">[${op.type.toUpperCase()}]</span>
                    <span class="log-plugin">${op.plugin}</span>
                    <span class="log-action">${op.action}</span>
                    <span class="log-status">${op.status}</span>
                    ${op.details ? `<div class="log-details">${op.details}</div>` : ''}
                `;
                logList.appendChild(entry);
            });
        }

        // Then render system commands
        if (logs.system && logs.system.length > 0) {
            const sysHeader = document.createElement('h5');
            sysHeader.textContent = '💻 System Commands';
            sysHeader.className = 'log-section-header system-section';
            logList.appendChild(sysHeader);

            logs.system.forEach(log => {
                const entry = document.createElement('div');
                const level = log.success ? 'success' : 'error';
                entry.className = `log-entry system-log ${level}`;
                entry.dataset.logType = 'system';
                const time = new Date(log.timestamp).toLocaleTimeString();
                entry.innerHTML = `
                    <span class="log-time">${time}</span>
                    <span class="log-type">[SYSTEM]</span>
                    <span class="log-command">${log.command}</span>
                    <span class="log-status">${log.success ? '✅' : '❌'}</span>
                `;
                if (log.result && log.result.stderr) {
                    entry.innerHTML += `<div class="log-details error">${log.result.stderr}</div>`;
                }
                logList.appendChild(entry);
            });
        }

        container.appendChild(logList);

        // Store logs for filtering
        this.currentLogs = logs;
    }

    filterLogs(filter) {
        const logEntries = document.querySelectorAll('.log-entry');
        const filterBtns = document.querySelectorAll('.filter-btn');
        const sectionHeaders = document.querySelectorAll('.log-section-header');
        
        // Update active button
        filterBtns.forEach(btn => {
            btn.classList.remove('active');
            // More precise button matching
            const btnText = btn.textContent.toLowerCase();
            if ((filter === 'all' && btnText === 'all') ||
                (filter === 'operations' && btnText === 'operations') ||
                (filter === 'system' && btnText === 'system') ||
                (filter === 'errors' && btnText === 'errors')) {
                btn.classList.add('active');
            }
        });

        // Show/hide section headers based on filter
        sectionHeaders.forEach(header => {
            if (filter === 'all') {
                header.style.display = 'block';
            } else if (filter === 'operations' && header.classList.contains('operations-section')) {
                header.style.display = 'block';
            } else if (filter === 'system' && header.classList.contains('system-section')) {
                header.style.display = 'block';
            } else {
                header.style.display = 'none';
            }
        });

        // Filter entries
        logEntries.forEach(entry => {
            if (filter === 'all') {
                entry.style.display = 'flex';
            } else if (filter === 'operations' && entry.dataset.logType === 'operations') {
                entry.style.display = 'flex';
            } else if (filter === 'system' && entry.dataset.logType === 'system') {
                entry.style.display = 'flex';
            } else if (filter === 'errors' && (entry.classList.contains('error') || entry.classList.contains('failed'))) {
                entry.style.display = 'flex';
            } else {
                entry.style.display = 'none';
            }
        });
    }

    // API helpers
    async apiGet(url) {
        const response = await fetch(url, {
            headers: {
                'Authorization': `Bearer ${this.token}`
            }
        });
        if (response.status === 401 || response.status === 403) {
            this.logout();
            throw new Error('Session expired');
        }
        return await response.json();
    }

    async apiPost(url, data = {}, method = 'POST') {
        const response = await fetch(url, {
            method: method,
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${this.token}`
            },
            body: JSON.stringify(data)
        });
        if (response.status === 401 || response.status === 403) {
            this.logout();
            throw new Error('Session expired');
        }
        return await response.json();
    }

