    renderGuestConversations(data) {
        // Update stats
        document.getElementById('total-conversations').textContent = data.totalConversations || 0;
        document.getElementById('active-today').textContent = data.activeToday || 0;
        document.getElementById('total-messages').textContent = data.totalMessages || 0;
        
        // Update table
        const tbody = document.getElementById('guests-tbody');
        tbody.innerHTML = '';
        
        if (!data.users || data.users.length === 0) {
            tbody.innerHTML = '<tr><td colspan="6">No guest conversations yet</td></tr>';
            return;
        }
        
        data.users.forEach(user => {
            const row = document.createElement('tr');
            
            // Determine type display
            const typeIcon = user.type === 'email' ? '📧' : '💬';
            const typeText = user.type === 'email' ? 'Email' : 'Telegram';
            
            // Truncate long usernames for display
            const displayUsername = user.username.length > 20 ? 
                user.username.substring(0, 20) + '...' : user.username;
            
            // Format dates more compactly
            const firstSeen = new Date(user.firstSeen).toLocaleDateString();
            const lastSeen = user.lastSeen ? new Date(user.lastSeen).toLocaleDateString() : '-';
            
            row.innerHTML = `
                <td class="type-cell" title="${typeText}">${typeIcon}</td>
                <td title="${user.userName || 'Unknown'}">${user.userName || 'Unknown'}</td>
                <td class="username-cell" title="${user.username}">${displayUsername}</td>
                <td class="messages-cell">${user.messageCount}</td>
                <td class="date-cell" title="${new Date(user.firstSeen).toLocaleString()}">${firstSeen}</td>
                <td class="date-cell" title="${user.lastSeen ? new Date(user.lastSeen).toLocaleString() : '-'}">${lastSeen}</td>
            `;
            tbody.appendChild(row);
        });
    }

    formatUptime(seconds) {
        const days = Math.floor(seconds / 86400);
        const hours = Math.floor((seconds % 86400) / 3600);
        const minutes = Math.floor((seconds % 3600) / 60);
        const parts = [];
        if (days > 0) parts.push(`${days}d`);
        if (hours > 0) parts.push(`${hours}h`);
        if (minutes > 0) parts.push(`${minutes}m`);
        return parts.join(' ') || '0m';
    }

    showNotification(message, type = 'info') {
        // Simple notification (you can enhance this with a toast library)
        const notification = document.createElement('div');
        notification.className = `notification ${type}`;
        notification.textContent = message;
        document.body.appendChild(notification);
        
        setTimeout(() => {
            notification.remove();
        }, 3000);
    }

    // Self-Modification Methods
    async loadSelfModStatus() {
        try {
            const response = await this.apiGet('/api/selfmod/status');
            if (response.success) {
                this.renderSelfModStatus(response.data);
            }
        } catch (error) {
            console.error('Failed to load self-mod status:', error);
        }
    }

    renderSelfModStatus(status) {
        // Update status
        const enabledEl = document.getElementById('selfmod-enabled');
        enabledEl.textContent = status.enabled ? 'ENABLED' : 'DISABLED';
        enabledEl.style.color = status.enabled ? '#4caf50' : '#f44336';
        
        // Update analysis-only toggle
        const analysisToggle = document.getElementById('analysis-only-toggle');
        if (analysisToggle) {
            analysisToggle.checked = status.analysisOnly !== false;
        }
        
        document.getElementById('selfmod-daily-count').textContent = 
            `${status.dailyImprovementCount}/${status.maxDailyImprovements}`;
        
        document.getElementById('selfmod-last-run').textContent = 
            status.lastCheckTime ? new Date(status.lastCheckTime).toLocaleString() : 'Never';
        
        // Update currently running status
        const runningEl = document.getElementById('selfmod-running');
        if (runningEl) {
            runningEl.textContent = status.isRunning ? 'YES' : 'NO';
            runningEl.style.color = status.isRunning ? '#4caf50' : '#888';
        }
        
        const branchEl = document.getElementById('selfmod-branch');
        const branchName = status.currentBranch || 'main';
        branchEl.textContent = branchName;
        branchEl.title = branchName;
        
        // Calculate next session time (runs at 4 AM and 4 PM)
        const nextEl = document.getElementById('selfmod-next');
        if (nextEl) {
            const now = new Date();
            const nextSession = new Date();
            const currentHour = now.getHours();
            
            if (currentHour < 4) {
                nextSession.setHours(4, 0, 0, 0);
            } else if (currentHour < 16) {
                nextSession.setHours(16, 0, 0, 0);
            } else {
                nextSession.setDate(nextSession.getDate() + 1);
                nextSession.setHours(4, 0, 0, 0);
            }
            
            nextEl.textContent = nextSession.toLocaleString();
        }
        
        // Update toggle button
        const toggleBtn = document.getElementById('selfmod-toggle');
        const toggleText = document.getElementById('selfmod-toggle-text');
        if (status.enabled) {
            toggleBtn.classList.remove('btn-danger');
            toggleBtn.classList.add('btn-warning');
            toggleText.textContent = 'Disable Self-Modification';
        } else {
            toggleBtn.classList.remove('btn-warning');
            toggleBtn.classList.add('btn-danger');
            toggleText.textContent = 'Enable Self-Modification';
        }
        
        // Update config form
        if (status.config) {
            document.getElementById('maxChangesPerSession').value = status.config.maxChangesPerSession;
            document.getElementById('maxDailyImprovements').value = status.config.maxDailyImprovements;
            document.getElementById('idleMinutes').value = status.config.idleMinutes;
            document.getElementById('checkIntervalMinutes').value = status.config.checkIntervalMinutes;
            document.getElementById('cpuThreshold').value = status.config.cpuThreshold;
            document.getElementById('memoryThreshold').value = status.config.memoryThreshold;
            
            if (status.config.scheduledHour !== null) {
                document.getElementById('scheduledHour').value = status.config.scheduledHour;
            }
            document.getElementById('scheduledMinute').value = status.config.scheduledMinute;
            
            // Update core upgrades first toggle
            document.getElementById('coreUpgradesFirst').checked = status.config.coreUpgradesFirst !== false;
        }
    }

