    async toggleSelfModification() {
        try {
            const response = await this.apiGet('/api/selfmod/status');
            if (!response.success) return;
            
            const currentlyEnabled = response.data.enabled;
            const action = currentlyEnabled ? 'disable' : 'enable';
            
            if (!currentlyEnabled && !confirm('Are you sure you want to enable self-modification? ALICE will be able to autonomously modify its own code during idle periods.')) {
                return;
            }
            
            const toggleResponse = await this.apiPost('/api/selfmod/toggle', { 
                enabled: !currentlyEnabled 
            });
            
            if (toggleResponse.success) {
                this.showNotification(
                    `Self-modification ${action}d successfully`, 
                    'success'
                );
                this.loadSelfModStatus();
            } else {
                this.showNotification(
                    `Failed to ${action} self-modification`, 
                    'error'
                );
            }
        } catch (error) {
            console.error('Failed to toggle self-modification:', error);
            this.showNotification('Error toggling self-modification', 'error');
        }
    }

    async runSelfModCheck() {
        try {
            const response = await this.apiPost('/api/selfmod/check', {});
            
            if (response.success) {
                this.showNotification(
                    response.message || 'Self-modification check started. Check logs for progress.', 
                    'success'
                );
                
                // Start polling for status updates
                this.startSelfModStatusPolling();
            } else {
                this.showNotification(
                    `Failed to start check: ${response.error}`, 
                    'error'
                );
            }
        } catch (error) {
            console.error('Failed to run self-mod check:', error);
            this.showNotification('Error running self-modification check', 'error');
        }
    }
    
    // Add polling mechanism for real-time status updates
    startSelfModStatusPolling() {
        // Clear any existing polling interval
        if (this.selfModPollingInterval) {
            clearInterval(this.selfModPollingInterval);
        }
        
        // Poll immediately
        this.loadSelfModStatus();
        
        // Poll every 2 seconds
        this.selfModPollingInterval = setInterval(async () => {
            const response = await this.apiGet('/api/selfmod/status');
            if (response.success) {
                this.renderSelfModStatus(response.data);
                
                // Stop polling when no longer running
                if (!response.data.isRunning) {
                    clearInterval(this.selfModPollingInterval);
                    this.selfModPollingInterval = null;
                }
            }
        }, 2000);
        
        // Safety: stop polling after 5 minutes regardless
        setTimeout(() => {
            if (this.selfModPollingInterval) {
                clearInterval(this.selfModPollingInterval);
                this.selfModPollingInterval = null;
            }
        }, 5 * 60 * 1000);
    }
    
    // Stop self-mod polling when switching tabs or cleaning up
    stopSelfModStatusPolling() {
        if (this.selfModPollingInterval) {
            clearInterval(this.selfModPollingInterval);
            this.selfModPollingInterval = null;
        }
    }

