    async loadGravatarOAuthStatus() {
        const connText = document.getElementById('gravatar-connection-text');
        const connectBtn = document.getElementById('gravatar-connect-btn');
        const disconnectBtn = document.getElementById('gravatar-disconnect-btn');
        if (!connText) return;

        try {
            const resp = await this.apiGet('/api/gravatar/oauth/status');
            if (resp.connected) {
                connText.innerHTML = '<i class="fas fa-check-circle" style="color: var(--success-color, #4caf50);"></i> Connected to Gravatar (OAuth)';
                if (connectBtn) connectBtn.style.display = 'none';
                if (disconnectBtn) disconnectBtn.style.display = '';
            } else {
                if (resp.hasClientId) {
                    connText.innerHTML = '<i class="fas fa-exclamation-circle" style="color: var(--warning-color, #ff9800);"></i> Not connected';
                    if (connectBtn) connectBtn.style.display = '';
                } else {
                    connText.innerHTML = '<i class="fas fa-info-circle" style="color: var(--text-secondary);"></i> OAuth not configured (set GRAVATAR_CLIENT_ID in .env)';
                    if (connectBtn) connectBtn.style.display = 'none';
                }
                if (disconnectBtn) disconnectBtn.style.display = 'none';
            }
        } catch (error) {
            connText.innerHTML = '<i class="fas fa-times-circle" style="color: var(--error-color, #f44336);"></i> Failed to check status';
            if (connectBtn) connectBtn.style.display = 'none';
            if (disconnectBtn) disconnectBtn.style.display = 'none';
        }
    }

    async connectGravatar() {
        try {
            const resp = await this.apiGet('/api/gravatar/oauth/authorize');
            if (resp.success && resp.authorizeUrl) {
                window.open(resp.authorizeUrl, '_blank');
                this.showNotification('Complete authorization in the new tab. The page will update when done.', 'info');
            } else {
                this.showNotification(resp.error || 'Failed to start OAuth flow', 'error');
            }
        } catch (error) {
            console.error('Gravatar connect error:', error);
            this.showNotification('Failed to start Gravatar connection', 'error');
        }
    }

    async disconnectGravatar() {
        if (!confirm('Disconnect Gravatar OAuth? Avatar uploads will fall back to API key.')) return;
        try {
            const resp = await this.apiPost('/api/gravatar/oauth/disconnect', {});
            if (resp.success) {
                this.showNotification('Gravatar disconnected', 'success');
                this.loadGravatarOAuthStatus();
            } else {
                this.showNotification(resp.error || 'Failed to disconnect', 'error');
            }
        } catch (error) {
            console.error('Gravatar disconnect error:', error);
            this.showNotification('Failed to disconnect Gravatar', 'error');
        }
    }

