    getFrequencyLabel(frequency) {
        const labels = {
            1: 'Daily',
            3: 'Every 3 days', 
            7: 'Weekly',
            14: 'Bi-weekly',
            30: 'Monthly',
            90: 'Quarterly'
        };
        return labels[frequency] || `Every ${frequency} days`;
    }

    updateNextReportTime(settings) {
        try {
            if (settings && settings.nextReport) {
                const nextReport = new Date(settings.nextReport);
                const formatted = nextReport.toLocaleString('en-US', {
                    weekday: 'short',
                    month: 'short',
                    day: 'numeric',
                    hour: '2-digit',
                    minute: '2-digit'
                });
                document.getElementById('next-report-time').textContent = formatted;
            } else {
                document.getElementById('next-report-time').textContent = 'Not scheduled';
            }
        } catch (error) {
            console.error('Error updating next report time:', error);
            document.getElementById('next-report-time').textContent = 'Unknown';
        }
    }

