    async viewEmail(emailId) {
        try {
            const response = await this.apiPost('/api/plugin', {
                plugin: 'email',
                action: 'getEmailById',
                emailId: emailId
            });
            
            if (response.success) {
                this.showEmailViewModal(response.email);
            } else {
                throw new Error(response.error || 'Failed to load email');
            }
        } catch (error) {
            console.error('Failed to view email:', error);
            this.showNotification('Error loading email: ' + error.message, 'error');
        }
    }

    showEmailViewModal(email) {
        // Populate email details
        document.getElementById('email-view-from').textContent = email.from || '';
        document.getElementById('email-view-to').textContent = email.to || '';
        document.getElementById('email-view-subject').textContent = email.subject || '';
        document.getElementById('email-view-date').textContent = email.sentDate ? 
            new Date(email.sentDate).toLocaleString() : 'Unknown';
        
        // Handle CC and BCC
        const ccField = document.getElementById('email-view-cc-field');
        const bccField = document.getElementById('email-view-bcc-field');
        
        if (email.cc) {
            document.getElementById('email-view-cc').textContent = email.cc;
            ccField.style.display = 'block';
        } else {
            ccField.style.display = 'none';
        }
        
        if (email.bcc) {
            document.getElementById('email-view-bcc').textContent = email.bcc;
            bccField.style.display = 'block';
        } else {
            bccField.style.display = 'none';
        }
        
        // Populate content
        document.getElementById('email-text-body').textContent = email.text || 'No text content';
        document.getElementById('email-html-body').textContent = email.html || 'No HTML content';
        
        // Render HTML preview safely
        const previewBody = document.getElementById('email-preview-body');
        if (email.html) {
            // Create a sandboxed iframe for HTML content
            previewBody.innerHTML = `
                <iframe 
                    srcdoc="${email.html.replace(/"/g, '&quot;')}" 
                    style="width: 100%; height: 100%; border: none;"
                    sandbox="allow-same-origin">
                </iframe>
            `;
        } else {
            previewBody.innerHTML = '<p>No HTML content to preview</p>';
        }
        
        // Reset to text view
        this.switchEmailContentView('text');
        
        // Show modal
        document.getElementById('email-view-modal').style.display = 'block';
    }

    switchEmailContentView(viewType) {
        // Hide all views
        document.querySelectorAll('.email-content-view').forEach(view => {
            view.style.display = 'none';
        });
        
        // Remove active class from all tabs
        document.querySelectorAll('.email-content-tab').forEach(tab => {
            tab.classList.remove('active');
        });
        
        // Show selected view
        document.getElementById(`email-${viewType}-content`).style.display = 'block';
        
        // Add active class to selected tab
        document.querySelector(`[onclick="dashboard.switchEmailContentView('${viewType}')"]`).classList.add('active');
    }

    closeEmailViewModal() {
        document.getElementById('email-view-modal').style.display = 'none';
    }

    // Project Management
    async loadProjects() {
        try {
            const response = await this.apiGet('/api/projects');
            if (response.success) {
                this.renderProjects(response.projects || []);
            } else {
                console.error('Projects API error:', response);
                this.showNotification(response.error || 'Failed to load projects', 'error');
                // Show error in the projects list area
                const container = document.getElementById('projects-list');
                container.innerHTML = `
                    <div class="error-state">
                        <i class="fas fa-exclamation-triangle"></i>
                        <p>Error: ${response.error || 'Failed to load projects'}</p>
                    </div>
                `;
            }
        } catch (error) {
            console.error('Failed to load projects:', error);
            this.showNotification('Failed to load projects', 'error');
        }
    }

    renderProjects(projects) {
        const container = document.getElementById('projects-list');
        
        if (!projects || projects.length === 0) {
            container.innerHTML = `
                <div class="empty-state">
                    <i class="fas fa-folder-open"></i>
                    <p>No projects yet</p>
                    <p class="text-muted">Create your first project to get started</p>
                </div>
            `;
            return;
        }

        container.innerHTML = '';
        projects.forEach(project => {
            const card = document.createElement('div');
            card.className = 'project-card';
            
            const statusClass = project.status === 'active' ? 'status-active' : 
                               project.status === 'completed' ? 'status-completed' : 
                               project.status === 'on-hold' ? 'status-hold' : 'status-planning';
            
            card.innerHTML = `
                <div class="project-header">
                    <h3><i class="fas fa-project-diagram"></i> ${project.name}</h3>
                    <span class="project-status ${statusClass}">${project.status}</span>
                </div>
                <p class="project-description">${project.description || 'No description'}</p>
                <div class="project-info">
                    <div class="project-stats">
                        <span><i class="fas fa-tasks"></i> ${project.taskCount || 0} tasks</span>
                        <span><i class="fas fa-code-branch"></i> ${project.features?.length || 0} features</span>
                        <span><i class="fas fa-calendar"></i> Created ${new Date(project.createdAt).toLocaleDateString()}</span>
                    </div>
                    <div class="project-actions">
                        <button onclick="dashboard.viewProject('${project.id}')" class="btn btn-sm btn-primary">
                            <i class="fas fa-eye"></i> View
                        </button>
                        <button onclick="dashboard.editProject('${project.id}')" class="btn btn-sm btn-secondary">
                            <i class="fas fa-edit"></i> Edit
                        </button>
                    </div>
                </div>
                ${project.progress ? `
                    <div class="project-progress">
                        <div class="progress-bar">
                            <div class="progress-fill" style="width: ${project.progress}%"></div>
                        </div>
                        <span class="progress-text">${project.progress}% complete</span>
                    </div>
                ` : ''}
            `;
            
            container.appendChild(card);
        });
    }

