    showSambaFileBrowser(mountId, data) {
        const html = `
            <div class="modal-overlay" id="sambaFileBrowser">
                <div class="modal" style="max-width: 800px;">
                    <div class="modal-header">
                        <h3><i class="fas fa-folder-open"></i> Browse: ${data.mountPoint}</h3>
                        <button class="modal-close" onclick="this.closest('.modal-overlay').remove()">×</button>
                    </div>
                    <div class="modal-body" style="max-height: 500px; overflow-y: auto;">
                        <div class="file-browser">
                            ${data.files.length > 0 ? 
                                `<ul class="file-list">
                                    ${data.files.map(file => `
                                        <li class="file-item">
                                            <i class="fas ${file.isDirectory ? 'fa-folder' : 'fa-file'}"></i>
                                            <span>${file.name}</span>
                                            ${!file.isDirectory ? `<span class="file-size">${this.formatFileSize(file.size)}</span>` : ''}
                                        </li>
                                    `).join('')}
                                </ul>` :
                                '<p>No files found in this mount point</p>'
                            }
                        </div>
                    </div>
                    <div class="modal-footer">
                        <p class="text-muted">Total: ${data.files.length} items</p>
                        <button class="btn btn-secondary" onclick="this.closest('.modal-overlay').remove()">Close</button>
                    </div>
                </div>
            </div>
        `;
        
        document.body.insertAdjacentHTML('beforeend', html);
    }

    formatFileSize(bytes) {
        if (bytes === 0) return '0 B';
        const k = 1024;
        const sizes = ['B', 'KB', 'MB', 'GB'];
        const i = Math.floor(Math.log(bytes) / Math.log(k));
        return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
    }

    escapeHtml(unsafe) {
        return unsafe
            .replace(/&/g, "&amp;")
            .replace(/</g, "&lt;")
            .replace(/>/g, "&gt;")
            .replace(/"/g, "&quot;")
            .replace(/'/g, "&#039;")
            .replace(/\n/g, "<br>");
    }

    // Convert URLs in text to clickable links (after escapeHtml)
    linkifyUrls(text) {
        const urlPattern = /(https?:\/\/[^\s<]+)/g;
        return text.replace(urlPattern, '<a href="$1" target="_blank" rel="noopener noreferrer">$1</a>');
    }

