            useTokenAddress: function(address) {
                document.getElementById('contractAddress').value = address;
                this.loadContract();
            },
            
            loadContract: async function() {
                const address = document.getElementById('contractAddress').value.trim();
                if (!address) {
                    dashboard.showNotification('Please enter a contract address', 'error');
                    return;
                }
                
                try {
                    // Try to load contract as token first
                    const response = await fetch(`/api/contracts/token/${address}?network=${this.currentNetwork}`, {
                        headers: { 'Authorization': `Bearer ${dashboard.token}` }
                    });
                    
                    if (response.ok) {
                        const tokenInfo = await response.json();
                        this.displayContractInfo(tokenInfo, 'ERC20');
                        
                        // Load standard ERC20 ABI
                        document.getElementById('standardAbiSelect').value = 'ERC20';
                        await this.loadStandardAbi();
                    } else {
                        // Try as NFT
                        const nftResponse = await fetch(`/api/contracts/nft/${address}?network=${this.currentNetwork}`, {
                            headers: { 'Authorization': `Bearer ${dashboard.token}` }
                        });
                        
                        if (nftResponse.ok) {
                            const nftInfo = await nftResponse.json();
                            this.displayContractInfo(nftInfo, 'ERC721');
                            
                            // Load standard ERC721 ABI
                            document.getElementById('standardAbiSelect').value = 'ERC721';
                            await this.loadStandardAbi();
                        } else {
                            dashboard.showNotification('Could not detect contract type. Please select an ABI.', 'warning');
                            document.getElementById('contractInfo').style.display = 'none';
                        }
                    }
                    
                    this.currentContract = address;
                } catch (error) {
                    console.error('Failed to load contract:', error);
                    dashboard.showNotification('Failed to load contract', 'error');
                }
            },
            
