                const projectsList = document.getElementById('projectsList');
                
                if (projects.length === 0) {
                    projectsList.innerHTML = '<p>No projects yet. Create your first Hardhat project!</p>';
                    return;
                }
                
                projectsList.innerHTML = projects.map(project => `
                    <div class="project-item" onclick="cryptoManager.loadProject('${project.name}')">
                        <div class="project-name">
                            <i class="fas fa-folder"></i> ${project.name}
                        </div>
                        <div class="project-info">
                            ${project.contracts.length} contracts
                        </div>
                    </div>
                `).join('');
